var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"맡겨 둔 기억을 되찾으러 왔다.","JPN":"預けた記憶を取り戻しに来た。","ENG":"I'm here to reclaim my memory.","TWN":"我來找回我託付的記憶。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼 처음부터 그렇게 얘기하면 됐잖아.","JPN":"じゃあ、最初からそう言いなさいよ。","ENG":"You could've led with that.","TWN":"那你一開始就應該這麼說。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"전사란 족속들은 이래서 상종하면 안 돼. 무식하게 힘부터 쓰고 본다니까.","JPN":"だから戦士は嫌いなんだよ。力づくで解決しようとするから。","ENG":"This is why I don't hang out with warriors. They just go straight to violence.","TWN":"你們這些戰士就知道動用武力，真不應該和你們有什麼往來。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"……그래도 제법이네.","JPN":"……でも、なかなかやるね。","ENG":"...Not bad, though.","TWN":"……不過非常不錯喔。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 이름과 기억을 되찾으러 왔다는 건, 클리포트게임을 무사히 넘겼단 거겠지?","JPN":"あなたの名前と記憶を取り戻しに来たってことは、クリフォトゲームを無事乗り越えたってことでしょ？","ENG":"If you're here to reclaim your name and memory, that must mean the Qliphoth Game is safely over.","TWN":"你來找回記憶，說明你順利度過了逆卡巴拉遊戲？"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 과정에서 <color=#ffd34c>녀석</color>이 멋대로 일을 추진한 건 썩 마음에 들진 않지만…","JPN":"その途中で<color=#ffd34c>奴</color>が勝手に仕事を進めたのはあまり気に入らないが……","ENG":"I'm not happy about the fact that <color=#ffd34c>he</color> went ahead with this during that process, but...","TWN":"雖然在這過程中，那<color=#ffd34c>傢伙</color>總是自作主張……"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"성과가 좋았다는 건 인정해야겠지.","JPN":"成果があったという点は認めるべきだろう。","ENG":"I'll have to admit, the outcome was pretty good.","TWN":"但不得不承認取得了不錯的成果。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"헹, 맨날 마음에 안 든다면서 걘 왜 한 번도 안 때리냐? 응? 나랑 다르게 가진 목숨이 하나뿐이라서?","JPN":"ふんっ、いつも気に入らないって言ってる割には一度も殴らなかったじゃない。私と違って、命が一つだけだから？","ENG":"Heh. You always say you don't like him, but why don't you ever hit him? Huh? Just because he only has one life, unlike me?","TWN":"哼，你既然那麼討厭他，為什麼從來都不會打他呢？嗯？是因為他只有一條命嗎？"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그게 아니면 실은 너 걔 좋아한다거나…","JPN":"それとも、実はあなた、あいつのことが好きだったり……","ENG":"Or is it because you like him–","TWN":"或者說你其實心裡是喜歡他的……"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야야- 야야야야야야야-! 그렇게 당기면 꼬리 끊어져! 끊어진다고…!","JPN":"ちょちょーちょっとちょっとちょっとちょっとー！　引っ張らないで尻尾とれちゃう！　とれるって……！","ENG":"Ow! Owwww oww oww! Stop tugging on my tail! It's going to fall off! It's falling off...!","TWN":"喂喂——呀啊啊啊啊啊——！尾巴會斷的！快放手……！"},"stage":{"bg":"PRISON_SPACE","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"헛소리 끝났으면 본론으로 넘어가.","JPN":"戯言は済んだか？　本題に入れ。","ENG":"Get to the point.","TWN":"廢話說完了吧，我們來談正事。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"조… 좋아.","JPN":"わ……わかったよ。","ENG":"F-fine.","TWN":"好……好吧。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"날 여기서 꺼내 줘. 답답해 죽을 지경이었거든.","JPN":"私をここから出して。息苦しくて死にそうだったの。","ENG":"Get me out of here. I'm dying of boredom.","TWN":"把我弄出去吧，我快悶死了。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내 요구는?","JPN":"私の要求は？","ENG":"What about my demands?","TWN":"我的要求呢？"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"일단 땅에 발부터 딛고나서 생각해 볼게.","JPN":"地上に着いたら考えるよ。","ENG":"I'll think about it after I set foot on earth.","TWN":"等我出去之後再考慮。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"거절하지. 네 녀석이 또 무슨 장난질을 하며 사라질지도 모르니까.","JPN":"断る。お前がまたどんな悪戯をして消えるかわからないからな。","ENG":"I refuse. You might play some trick and disappear again.","TWN":"我拒絕。誰知道你又會搞什麼把戲。"},"stage":{"bg":"PRISON_SPACE","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};